// components/SearchBar.jsx
import React, { useState } from 'react';

export default function SearchBar({ onAdd, disabled, cityCount }) {
  const [value, setValue] = useState('');

  const handleAdd = () => {
    const trimmed = value.trim();
    if (!trimmed) return;
    onAdd(trimmed);
    setValue('');
  };

  return (
    <div style={styles.wrapper}>
      <input
        style={styles.input}
        type="text"
        placeholder="Enter a city name (e.g. Tokyo, Mumbai, London)..."
        value={value}
        onChange={(e) => setValue(e.target.value)}
        onKeyDown={(e) => e.key === 'Enter' && !disabled && handleAdd()}
        disabled={disabled}
        aria-label="City name"
      />
      <button
        style={{
          ...styles.btn,
          opacity: disabled || !value.trim() ? 0.5 : 1,
        }}
        onClick={handleAdd}
        disabled={disabled || !value.trim()}
      >
        {disabled ? 'Loading...' : 'Add city'}
      </button>
      <span style={styles.counter}>{cityCount}/5</span>
    </div>
  );
}

const styles = {
  wrapper: {
    display: 'flex',
    gap: 10,
    alignItems: 'center',
    flexWrap: 'wrap',
    marginBottom: 20,
  },
  input: {
    flex: 1,
    minWidth: 200,
    padding: '10px 14px',
    border: '1px solid #d0d5dd',
    borderRadius: 10,
    fontSize: 14,
    outline: 'none',
    background: '#fff',
  },
  btn: {
    padding: '10px 20px',
    background: '#378ADD',
    color: '#fff',
    border: 'none',
    borderRadius: 10,
    fontSize: 14,
    fontWeight: 600,
    transition: 'opacity 0.2s',
  },
  counter: {
    fontSize: 13,
    color: '#aaa',
    whiteSpace: 'nowrap',
  },
};
